import{_ as e,o as t,c as r,ay as a}from"./chunks/framework.-lzFfN-z.js";const n="/CoreFront-EndConcepts/browserCache.png",u=JSON.parse('{"title":"浏览器缓存机制","description":"","frontmatter":{},"headers":[],"relativePath":"networkAndBrowsers/browserCache.md","filePath":"networkAndBrowsers/browserCache.md","lastUpdated":1779843930000}'),c={name:"networkAndBrowsers/browserCache.md"};function i(s,o,l,d,g,h){return t(),r("div",null,[...o[0]||(o[0]=[a('<h1 id="浏览器缓存机制" tabindex="-1">浏览器缓存机制 <a class="header-anchor" href="#浏览器缓存机制" aria-label="Permalink to &quot;浏览器缓存机制&quot;">​</a></h1><h2 id="_1-什么是浏览器缓存-为什么要缓存" tabindex="-1">1. 什么是浏览器缓存？为什么要缓存？ <a class="header-anchor" href="#_1-什么是浏览器缓存-为什么要缓存" aria-label="Permalink to &quot;1. 什么是浏览器缓存？为什么要缓存？&quot;">​</a></h2><p><strong>浏览器缓存（Browser Caching）</strong> 是指浏览器在本地磁盘或内存中保存用户最近请求过的网络资源（如 HTML、CSS、JavaScript 文件、图片等），当用户再次访问该资源时，浏览器可以直接从本地读取，而无需再次向服务器发起网络请求。</p><p><strong>核心优势：</strong></p><ul><li><strong>减少网络延迟，加快页面打开速度</strong>（最核心的用户体验提升）。</li><li><strong>减少服务器的压力</strong>，节省服务器带宽。</li><li><strong>在网络极差或断网状态下，依然能提供基础的页面访问</strong>。</li></ul><h2 id="_2-缓存的存放位置" tabindex="-1">2. 缓存的存放位置 <a class="header-anchor" href="#_2-缓存的存放位置" aria-label="Permalink to &quot;2. 缓存的存放位置&quot;">​</a></h2><p>按读取优先级从高到低，浏览器缓存可以分为以下四个位置：</p><ul><li><strong>Service Worker：</strong> 运行在浏览器背后的独立线程，常用于实现离线缓存（PWA技术）。它可以自由控制缓存哪些文件、如何匹配缓存等，灵活性最高。</li><li><strong>Memory Cache（内存缓存）：</strong> 包含当前页面中已经抓取到的资源（如页面上下载的样式、脚本、图片）。读取速度极快，但<strong>存活时间短</strong>，一旦关闭 Tab 页，内存缓存就会被释放。</li><li><strong>Disk Cache（磁盘缓存）：</strong> 存储在硬盘中的缓存。读取速度稍慢，但<strong>容量大、存储时间长</strong>。绝大部分的缓存都来自 Disk Cache。</li><li><strong>Push Cache（推送缓存）：</strong> HTTP/2 中的新特性。只在会话（Session）中存在，一旦会话结束就被释放。</li></ul><h2 id="_3-强缓存-strong-cache" tabindex="-1">3. 强缓存 (Strong Cache) <a class="header-anchor" href="#_3-强缓存-strong-cache" aria-label="Permalink to &quot;3. 强缓存 (Strong Cache)&quot;">​</a></h2><p>强缓存是最高效的缓存方式。当浏览器判断命中强缓存时，<strong>完全不会向服务器发送任何网络请求</strong>，而是直接从本地（Memory Cache 或 Disk Cache）读取资源。</p><p>在浏览器的 Network 面板中，你会看到状态码为 <code>200 OK (from memory cache)</code> 或 <code>200 OK (from disk cache)</code>。</p><p>强缓存通过 HTTP 响应头中的两个字段来控制：<code>Expires</code> 和 <code>Cache-Control</code>。</p><h3 id="_3-1-expires-http-1-0-产物" tabindex="-1">3.1 Expires (HTTP/1.0 产物) <a class="header-anchor" href="#_3-1-expires-http-1-0-产物" aria-label="Permalink to &quot;3.1 Expires (HTTP/1.0 产物)&quot;">​</a></h3><ul><li><strong>作用</strong>：服务器返回一个<strong>绝对的过期时间</strong>（GMT 格式的时间戳）。在此时刻之前，浏览器都会直接使用本地缓存。</li><li><strong>示例</strong>：<code>Expires: Wed, 21 Oct 2026 07:28:00 GMT</code></li><li><strong>致命缺陷</strong>：它依赖于客户端（用户电脑）的系统时间。如果用户的本地时间与服务器时间不一致，或者用户手动修改了本地时间，那么缓存的判断就会完全失效。因此，它现在基本上被淘汰了，仅作为向后兼容的保留手段。</li></ul><h3 id="_3-2-cache-control-http-1-1-标准-目前的主流" tabindex="-1">3.2 Cache-Control (HTTP/1.1 标准，目前的主流) <a class="header-anchor" href="#_3-2-cache-control-http-1-1-标准-目前的主流" aria-label="Permalink to &quot;3.2 Cache-Control (HTTP/1.1 标准，目前的主流)&quot;">​</a></h3><ul><li><strong>作用</strong>：为了克服 <code>Expires</code> 的缺陷，<code>Cache-Control</code> 使用<strong>相对时间</strong>来控制缓存。</li><li><strong>最高优先级</strong>：如果同时存在 <code>Expires</code> 和 <code>Cache-Control</code>，浏览器会<strong>优先遵循 <code>Cache-Control</code></strong>。</li><li><strong>常见指令</strong>： <ul><li><strong><code>max-age=&lt;seconds&gt;</code></strong>：最重要的指令。表示资源从被请求的那一刻起，在指定的秒数内有效。例如 <code>Cache-Control: max-age=31536000</code> 表示缓存一年。在这期间内，直接走强缓存。</li><li><strong><code>no-cache</code></strong>：<strong>（容易误解）<strong>它的意思</strong>不是</strong>“不缓存”，而是“可以缓存，但在每次使用前，必须向服务器发送请求，<strong>进行协商缓存的验证</strong>”。</li><li><strong><code>no-store</code></strong>：这才是真正的“绝对不缓存”。浏览器和任何中间代理都不允许存储这个响应的任何内容。每次必须向服务器发完整请求。</li><li><strong><code>public</code></strong>：表示该响应可以被任何对象（包括客户端浏览器、CDN 节点、代理服务器等）缓存。</li><li><strong><code>private</code></strong>：表示该响应是针对单个用户的，只能被客户端浏览器缓存，中间的代理服务器（CDN）不能缓存。这是默认值。</li></ul></li></ul><h2 id="_4-协商缓存-negotiation-cache" tabindex="-1">4. 协商缓存 (Negotiation Cache) <a class="header-anchor" href="#_4-协商缓存-negotiation-cache" aria-label="Permalink to &quot;4. 协商缓存 (Negotiation Cache)&quot;">​</a></h2><p>当<strong>强缓存失效</strong>（即没有设置强缓存，或者 <code>max-age</code> 已过期，或者设置了 <code>no-cache</code>），浏览器就会向服务器发起请求，<strong>验证本地缓存的内容是否仍然是最新版本</strong>。这个验证过程就是协商缓存。</p><p>协商缓存需要客户端和服务器互相配合，通过两对特殊的 HTTP 头部字段来实现。</p><h3 id="_4-1-last-modified-if-modified-since-基于修改时间" tabindex="-1">4.1 Last-Modified / If-Modified-Since (基于修改时间) <a class="header-anchor" href="#_4-1-last-modified-if-modified-since-基于修改时间" aria-label="Permalink to &quot;4.1 Last-Modified / If-Modified-Since (基于修改时间)&quot;">​</a></h3><ol><li><strong>初次请求</strong>：服务器在返回资源时，会在响应头中加上 <code>Last-Modified</code>，表示这个资源在服务器上的<strong>最后修改时间</strong>。 <ul><li><code>Last-Modified: Fri, 12 Feb 2026 15:00:00 GMT</code></li></ul></li><li><strong>再次请求</strong>：当缓存过期，浏览器再次请求该资源时，会在请求头中自动加上 <code>If-Modified-Since</code>，其值就是上次收到的 <code>Last-Modified</code> 的值。</li><li><strong>服务器比对</strong>：服务器收到请求后，拿 <code>If-Modified-Since</code> 的时间与该资源在服务器上当前的最后修改时间进行比对。 <ul><li><strong>如果没有修改</strong>：服务器返回状态码 <strong><code>304 Not Modified</code></strong>，且不返回资源正文（Body 为空）。这告诉浏览器：“资源没变，你继续用你本地的旧缓存吧。”（这就是协商缓存命中的表现）。</li><li><strong>如果已修改</strong>：服务器返回状态码 <code>200 OK</code>，并带上最新的资源正文和新的 <code>Last-Modified</code> 时间。</li></ul></li></ol><ul><li><strong>缺陷</strong>： <ul><li><code>Last-Modified</code> 的时间精度只能精确到<strong>秒</strong>。如果一个文件在 1 秒内被修改了多次，它无法察觉。</li><li>如果某些文件被定时打开并重新保存，但<strong>内容根本没变</strong>，<code>Last-Modified</code> 时间也会更新，导致本可重用的缓存失效，造成不必要的重新下载。</li></ul></li></ul><h3 id="_4-2-etag-if-none-match-基于文件内容的唯一标识" tabindex="-1">4.2 ETag / If-None-Match (基于文件内容的唯一标识) <a class="header-anchor" href="#_4-2-etag-if-none-match-基于文件内容的唯一标识" aria-label="Permalink to &quot;4.2 ETag / If-None-Match (基于文件内容的唯一标识)&quot;">​</a></h3><p>为了解决时间精度的缺陷，HTTP/1.1 引入了 ETag。</p><ol><li><strong>初次请求</strong>：服务器在返回资源时，根据资源的内容生成一个<strong>唯一标识符</strong>（通常是一段哈希值/指纹），放在响应头的 <code>ETag</code> 字段中。只要文件内容改变，ETag 就会改变。 <ul><li><code>ETag: &quot;33a64df551425fcc55e4d42a148795d9f25f89d4&quot;</code></li></ul></li><li><strong>再次请求</strong>：浏览器再次请求时，会在请求头中加上 <code>If-None-Match</code>，其值就是上次收到的 <code>ETag</code>。</li><li><strong>服务器比对</strong>：服务器拿 <code>If-None-Match</code> 的值与资源当前的 ETag 进行严格的字符串比对。 <ul><li><strong>如果匹配（说明内容没变）</strong>：返回 <strong><code>304 Not Modified</code></strong>，浏览器继续用缓存。</li><li><strong>如果不匹配（说明内容变了）</strong>：返回 <code>200 OK</code> 和新内容、新 ETag。</li></ul></li></ol><ul><li><strong>最高优先级</strong>：在协商缓存中，<strong><code>ETag</code> 的优先级高于 <code>Last-Modified</code></strong>。如果同时存在，服务器会优先验证 ETag。</li></ul><h2 id="_4-缓存机制的完整流程梳理" tabindex="-1">4. 缓存机制的完整流程梳理 <a class="header-anchor" href="#_4-缓存机制的完整流程梳理" aria-label="Permalink to &quot;4. 缓存机制的完整流程梳理&quot;">​</a></h2><ol><li>浏览器尝试发起一个 HTTP 请求。</li><li><strong>检查强缓存</strong>：浏览器查找本地是否存在该资源的缓存记录，并检查 <code>Cache-Control</code> (如 <code>max-age</code>) 判断是否过期。 <ul><li><strong>未过期</strong>：命中强缓存，直接从本地读取并返回 <code>200 (from cache)</code>。请求结束。</li><li><strong>已过期（或存在 <code>no-cache</code>）</strong>：强缓存失效，准备发起网络请求进行<strong>协商缓存</strong>。</li></ul></li><li><strong>准备协商请求</strong>：浏览器提取之前保存的 <code>ETag</code> 和 <code>Last-Modified</code>，并将它们分别赋值给请求头 <code>If-None-Match</code> 和 <code>If-Modified-Since</code>，发送给服务器。</li><li><strong>服务器验证（协商缓存）</strong>： <ul><li>服务器优先比对 <code>ETag</code>，再比对 <code>Last-Modified</code>。</li><li><strong>未修改</strong>：服务器认为客户端的缓存仍然可用，返回 <strong><code>304 Not Modified</code></strong>，只带头部，不带 Body。浏览器收到 304 后，更新本地缓存的过期时间，并从本地加载资源。请求结束。</li><li><strong>已修改（或服务器没有这两个验证头）</strong>：缓存失效，服务器返回 <strong><code>200 OK</code></strong>，附带全新的资源数据以及新的缓存头信息。浏览器将新资源存入缓存。请求结束。</li></ul></li></ol><p><img src="'+n+'" alt="Logo" data-zoomable="true"></p><h2 id="_5-常见问题-faq" tabindex="-1">5. 常见问题 (FAQ) <a class="header-anchor" href="#_5-常见问题-faq" aria-label="Permalink to &quot;5. 常见问题 (FAQ)&quot;">​</a></h2><h3 id="_5-1-用户操作对缓存有什么影响" tabindex="-1">5.1 用户操作对缓存有什么影响？ <a class="header-anchor" href="#_5-1-用户操作对缓存有什么影响" aria-label="Permalink to &quot;5.1 用户操作对缓存有什么影响？&quot;">​</a></h3><ul><li><strong>地址栏输入 URL 回车 / 点击书签 / 点击超链接</strong>：这是最正常的用户行为，浏览器会严格按照上述**完整的缓存机制（强缓存优先，失效再协商）**来执行。</li><li><strong>按 F5 刷新页面 / 点击浏览器刷新按钮</strong>：浏览器认为用户希望看到稍微新一点的内容。它会<strong>强制忽略所有强缓存</strong>（即便 <code>max-age</code> 没到期），向服务器发送请求。但在请求中依然会带上 <code>If-None-Match</code>/<code>If-Modified-Since</code>，也就是<strong>只进行协商缓存</strong>。如果资源没变，服务器依然返回 304。</li><li><strong>按 Ctrl + F5 强制刷新 (Hard Reload)</strong>：浏览器认为用户遇到了严重问题，必须获取绝对最新的版本。浏览器会<strong>同时忽略强缓存和协商缓存</strong>。它在发送请求时会带上 <code>Cache-Control: no-cache</code> 并且丢弃验证头（不带 If-None-Match），迫使服务器必须返回 <code>200 OK</code> 和完整的最新资源。</li></ul><h3 id="_5-2-from-memory-cache-和-from-disk-cache-的区别是什么" tabindex="-1">5.2 <code>from memory cache</code> 和 <code>from disk cache</code> 的区别是什么？ <a class="header-anchor" href="#_5-2-from-memory-cache-和-from-disk-cache-的区别是什么" aria-label="Permalink to &quot;5.2 `from memory cache` 和 `from disk cache` 的区别是什么？&quot;">​</a></h3><ul><li><strong>Memory Cache (内存缓存)</strong>：读取速度极快，但持续性很短。通常用于缓存<strong>正在当前网页上使用</strong>的资源（如网页中加载好的多张图片、已经执行过的 JS/CSS 脚本）。<strong>一旦你关闭了这个浏览器的 Tab 标签页，内存缓存就会被清空。</strong></li><li><strong>Disk Cache (磁盘缓存)</strong>：读取速度稍慢（因为需要读写硬盘），但容量大，且可以持久保存。哪怕你重启了电脑，只要缓存没过期，依然可以从磁盘中读取。大文件或者很少被修改的文件通常会被放入磁盘缓存。</li><li><strong>分配策略</strong>：浏览器有自己复杂的启发式算法来决定放哪里。一般来说，小的、频繁使用的资源放内存；大的、长期有效的放磁盘。</li></ul><h3 id="_5-3-如何配置才能让前端发版-更新代码-后-用户立刻能看到最新效果-而不用手动清缓存" tabindex="-1">5.3 如何配置才能让前端发版（更新代码）后，用户立刻能看到最新效果，而不用手动清缓存？ <a class="header-anchor" href="#_5-3-如何配置才能让前端发版-更新代码-后-用户立刻能看到最新效果-而不用手动清缓存" aria-label="Permalink to &quot;5.3 如何配置才能让前端发版（更新代码）后，用户立刻能看到最新效果，而不用手动清缓存？&quot;">​</a></h3><p>这是前端工程化中最经典的问题。最佳实践是 <strong>“长缓存时间 + 文件名哈希 (Hash)”</strong> 组合拳：</p><ul><li><strong>对入口 HTML 文件</strong>：通常配置<strong>不进行强缓存</strong>，每次都必须验证（<code>Cache-Control: no-cache</code>）甚至不缓存（<code>no-store</code>）。因为 HTML 文件的内容很少，每次下载不耗时，它是后续所有资源加载的起点。</li><li><strong>对静态资源 (JS/CSS/图片等)</strong>：在构建工具（如 Webpack/Vite）打包时，在文件名中加入基于内容的 Hash 值（例如 <code>app.v2a3bf1.js</code>）。</li><li><strong>配置强缓存</strong>：在服务器上为这些带 Hash 的静态资源配置<strong>超长的强缓存时间</strong>（例如一年：<code>Cache-Control: max-age=31536000, immutable</code>）。</li></ul><p><strong>原理</strong>：</p><ul><li>只要你没改代码，文件名就不会变，用户访问时直接命中本地强缓存，速度飞快。</li><li>当你修改了某行代码并重新打包发版后，该文件的 Hash 值发生变化，生成了一个全新的文件名（如 <code>app.v8c9d0f.js</code>）。</li><li>用户再次访问时，浏览器请求入口 HTML 文件（HTML 不走强缓存，总能拉到最新版）。</li><li>最新的 HTML 文件里引用了新的 JS 文件名。由于这是一个浏览器从未见过的全新 URL，它根本没有本地缓存，只能老老实实去服务器下载最新代码。从而完美解决了缓存更新问题。</li></ul><h3 id="_5-4-为什么有了-etag-还要保留-last-modified" tabindex="-1">5.4 为什么有了 ETag 还要保留 Last-Modified？ <a class="header-anchor" href="#_5-4-为什么有了-etag-还要保留-last-modified" aria-label="Permalink to &quot;5.4 为什么有了 ETag 还要保留 Last-Modified？&quot;">​</a></h3><ul><li>生成 ETag 通常需要读取文件内容并计算哈希值，这是一个消耗服务器 CPU 性能的操作，特别是对于体积很大的文件。</li><li>如果服务器判断出读取 Last-Modified 就能满足大部分场景的需求，可以节省计算 ETag 的开销。它们通常是搭配使用的，互为补充。</li></ul><h3 id="_5-5-cache-control-no-cache-和-cache-control-no-store-的区别是什么" tabindex="-1">5.5 <code>Cache-Control: no-cache</code> 和 <code>Cache-Control: no-store</code> 的区别是什么？ <a class="header-anchor" href="#_5-5-cache-control-no-cache-和-cache-control-no-store-的区别是什么" aria-label="Permalink to &quot;5.5 `Cache-Control: no-cache` 和 `Cache-Control: no-store` 的区别是什么？&quot;">​</a></h3><ul><li><strong><code>no-cache</code></strong>：代表客户端<strong>可以</strong>缓存资源，但在使用缓存前，<strong>必须向服务器发送请求进行验证（即走协商缓存路线）</strong>。如果服务器回复 304，就使用缓存；如果回复 200，就用新的。</li><li><strong><code>no-store</code></strong>：代表绝对禁止任何形式的缓存（包括浏览器、中间代理服务器、CDN 等）。每次请求都必须像第一次那样，从服务器拉取完整的资源。通常用于极度敏感的数据（如银行流水页面）。</li></ul>',43)])])}const m=e(c,[["render",i]]);export{u as __pageData,m as default};
